using ArgParams = struct { unsigned int vecwidth; };

using benchmark_clock = std::chrono::steady_clock;

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_kernel(Element* data, Element* sum_out, size_t chunk_start) {
  Element sum = 0;
  Element f = data[chunk_start];

  for (size_t i = 0; i < static_chunk_size; i++) {
    Element t = data[chunk_start + i];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }
  sum_out[0] = sum;
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src, Element* src_d) {
  constexpr size_t static_chunk_size = 4096;
  Element sum = 0;
  Element* sum_d;
  cudaMalloc(&sum_d, sizeof(Element));

  size_t num_chunks = len / static_chunk_size;

  for (size_t chunk = 0; chunk < num_chunks; chunk++) {
    bench_block_kernel<Element, compute_iterations, static_chunk_size>(src_d, sum_d, chunk * static_chunk_size);
    Element partial_sum;
    cudaMemcpy(&partial_sum, sum_d, sizeof(Element), cudaMemcpyDeviceToHost);
    sum += partial_sum;
  }

  cudaMemcpy(src, src_d, len * sizeof(Element), cudaMemcpyDeviceToHost);
  src[0] = sum;
  cudaFree(sum_d);
  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);
  auto timer_start = benchmark_clock::now();

  double* ptr = (double*)c;
  double* ptr_d;
  cudaMalloc(&ptr_d, num_elements * sizeof(double));
  cudaMemcpy(ptr_d, ptr, num_elements * sizeof(double), cudaMemcpyHostToDevice);

  bench_cuda<double, 16>(num_elements, 1., -1., ptr, ptr_d);

  cudaFree(ptr_d);
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  float* c_as_float = (float*)c;
  float* c_as_float_d;
  cudaMalloc(&c_as_float_d, cs.element_count<float>() * sizeof(float));
  cudaMemcpy(c_as_float_d, c_as_float, cs.element_count<float>() * sizeof(float), cudaMemcpyHostToDevice);

  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float, c_as_float_d);
    });
  });
  cudaFree(c_as_float_d);

  double* c_as_double = (double*)c;
  double* c_as_double_d;
  cudaMalloc(&c_as_double_d, cs.element_count<double>() * sizeof(double));
  cudaMemcpy(c_as_double_d, c_as_double, cs.element_count<double>() * sizeof(double), cudaMemcpyHostToDevice);

  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double, c_as_double_d);
    });
  });
  cudaFree(c_as_double_d);

  int* c_as_int = (int*)c;
  int* c_as_int_d;
  cudaMalloc(&c_as_int_d, cs.element_count<int>() * sizeof(int));
  cudaMemcpy(c_as_int_d, c_as_int, cs.element_count<int>() * sizeof(int), cudaMemcpyHostToDevice);

  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int, c_as_int_d);
    });
  });
  cudaFree(c_as_int_d);

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp * 1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp * 1000. / (1000. * 1000. * 1000.)
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp * 1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp * 1000. / (1000. * 1000. * 1000.)
            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) / static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int * 1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int * 1000. / (1000. * 1000. * 1000.)
            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
